  padding: '9px 12px',
  borderRadius: '10px',
  border: '1.5px solid #E9EDE8',
  fontSize: '0.85rem',
  fontWeight: '600',
  color: '#374151',
  outline: 'none',
  background: '#fff',
  cursor: 'pointer'
};
const pageBtn = {
  width: '30px',
  height: '30px',
  borderRadius: '8px',
  border: '1.5px solid #E9EDE8',
  background: '#fff',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  fontSize: '0.8rem',
  fontWeight: '700',
  cursor: 'pointer',
  color: '#374151'
};
